INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'sacramento'), 'R-1', 'r-1', 'Single-Unit Dwelling Zone', 'This zone is intended to provide areas for single-unit dwellings and to protect the characteristics of existing single-unit neighborhoods. It also allows for public and quasi-public uses, and similar and compatible uses appropriate in a medium-density residential environment.', 35, NULL, 5200, NULL, 20, 15, 5, 'See Chapter 17.608 for parking requirements.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r-1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'sacramento') AND pu.name IN ('Dwelling, single-unit', 'Dwelling, duplex (limited to corner lots)', 'Model home temporary sales office', 'Community market (if primary use is not single-unit or duplex dwelling)', 'Solar energy system, commercial (city property)', 'Aquaculture, private garden, and urban beekeeping') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'sacramento'), 'R-2', 'r-2', 'Duplex Dwelling Zone', 'This zone is intended to provide areas for a variety of housing types at densities in the range of 6.1 to 12.0 units per acre. It also provides for public and quasi-public uses, and similar and compatible uses appropriate in a medium-density residential environment.', NULL, NULL, NULL, NULL, 15, 15, 5, 'See Chapter 17.608 for parking requirements.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
