INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'sacramento'), 'R-3', 'r-3', 'Multi-Unit Dwelling Zone', 'The R-3 Zone is intended to provide areas for a wide variety of high-density residential development, including single-unit attached, townhouses, condominiums, and apartment buildings. It also accommodates public and quasi-public uses, and similar compatible uses.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'See Chapter 17.608 for parking requirements.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
