INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'sacramento'), 'M-1', 'm-1', 'Light Industrial Zone', 'This zone is intended to accommodate light manufacturing, processing, assembly, research, wholesale, and storage uses. It also provides for public and quasi-public uses, and similar and compatible uses.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'See Chapter 17.608 for parking requirements.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'm-1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'sacramento') AND pu.name IN ('Light manufacturing', 'Warehousing', 'Wholesale trade', 'Research and development', 'Marijuana testing', 'Community clinic') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'sacramento'), 'RMX', 'rmx', 'Residential Mixed Use Zone', 'This zone is intended to provide for mixed-use developments that include a mix of residential and office/commercial or single-use residential, office, or commercial, with an emphasis on non-residential uses.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Off-street parking is not required for nonresidential uses in mixed-use buildings where at least 50% of the building''s square footage is residential.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
